Zustand est idéal pour un projet de taille moyenne comme un e-commerce : API simple, pas de boilerplate, performances optimales (pas de re-renders inutiles). Voici un store auth :
```js
import { create } from 'zustand';
import { persist } from 'zustand/middleware';

const useAuthStore = create(persist(
  (set) => ({
    user: null,
    token: null,
    login: (user, token) => set({ user, token }),
    logout: () => set({ user: null, token: null }),
  }),
  { name: 'auth-storage' }
));
```

```js
const useCartStore = create((set, get) => ({
  items: [],
  addItem: (product) => set((state) => {
    const existing = state.items.find(i => i.id === product.id);
    if (existing) {
      return { items: state.items.map(i => i.id === product.id ? { ...i, quantity: i.quantity + 1 } : i) };
    }
    return { items: [...state.items, { ...product, quantity: 1 }] };
  }),
  updateQuantity: (id, quantity) => set({ items: get().items.map(i => i.id === id ? { ...i, quantity } : i) }),
  removeItem: (id) => set({ items: get().items.filter(i => i.id !== id) }),
  getTotal: () => {
    const subtotal = get().items.reduce((sum, i) => sum + i.price * i.quantity, 0);
    return subtotal * 1.19; // TVA 19%
  }
}));
```

