import { useLoaderData } from 'react-router-dom';

function ProductPage() {
  const { product } = useLoaderData();
  const finalPrice = product.discount 
    ? product.price * (1 - product.discount / 100) 
    : product.price;
  return (
    <div>
      <h1>{product.name}</h1>
      <p>Prix : {finalPrice.toFixed(2)} FCFA</p>
    </div>
  );
}
